mapper.sql:
SELECT A.* , U.USER_ID AS REP_USER_ID , U.USERNM AS REP_USER_NM
-- 법정, 공개과목 Default 주차, 교시, 컨텐츠 아이디 조회 , ( SELECT * FROM ( SELECT LCTR_SCHDL_ID FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = A.SBJCT_ID AND LCTR_SCHDL_SEQ = 1 AND DELYN = 'N' ) A WHERE ROWNUM = 1 ) AS LCTR_SCHDL_ID , ( SELECT * FROM ( SELECT SBJCT_LCTR_CLASTM_ID FROM TB_LMS_SBJCT_LCTR_CLASTM AA JOIN TB_LMS_SBJCT_LCTR_SCHDL BB ON AA.LCTR_SCHDL_ID = BB.LCTR_SCHDL_ID AND BB.LCTR_SCHDL_SEQ = 1 AND BB.DELYN = 'N' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.LCTR_CLASTM_SEQ = 1 ) A WHERE ROWNUM = 1 ) AS SBJCT_LCTR_CLASTM_ID , ( SELECT * FROM ( SELECT SBJCT_LCTR_CONTS_ID FROM TB_LMS_SBJCT_LCTR_CONTS AA JOIN TB_LMS_SBJCT_LCTR_CLASTM BB ON AA.SBJCT_LCTR_CLASTM_ID = BB.SBJCT_LCTR_CLASTM_ID AND BB.LCTR_CLASTM_SEQ = 1 JOIN TB_LMS_SBJCT_LCTR_SCHDL CC ON BB.LCTR_SCHDL_ID = CC.LCTR_SCHDL_ID AND CC.LCTR_SCHDL_SEQ = 1 AND CC.DELYN = 'N' WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.LCTR_CONTS_SEQ = 1 ) A WHERE ROWNUM = 1 ) AS SBJCT_LCTR_CONTS_ID
FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_SBJCT_ADM B ON A.SBJCT_OFRNG_ID = B.SBJCT_OFRNG_ID AND B.SBJCT_ADM_TYCD = 'PROF' LEFT JOIN TB_LMS_USER U ON U.USER_ID = A.RGTR_ID AND U.ORG_ID = #{orgId} WHERE 1 = 1 AND A.DELYN = 'N' AND A.SBJCT_ID = #{sbjctId}
AND C.CRS_SMSTR_ID = #{termCd}
AND A.SBJCT_ID = #{crsCreCd}
AND A.SBJCT_YR = #{creYear}
AND A.CRS_ID = #{creTerm}
AND A.DEPT_ID = #{deptId}
AND A.USEYN = #{useYn}
AND A.ATNDLC_CERT_STSCD = #{enrlCertStatus}
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND A.SBJCT_TYCD = #{crsTypeCd}
AND A.SBJCT_TYCD IN
#{item}
AND ( LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = D.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

