		SELECT COUNT(1) FROM (

		) A

/* SQL ID : CrecrsDAO.listCrsCreDropdown 설 명 : 강의실 드롭다운 목록 */ SELECT TLSO.SBJCT_OFRNG_ID , TLSO.SBJCTNM , TLSO.DVCLAS_NO , TLO.ORG_TYCD , TLSO.DEPT_ID , TLSO.SBJCT_TYCD , TLSO.CRS_MSTR_ID , TLSO.SMSTR_CHRT_ID , TLO.ORG_ID FROM TB_LMS_SBJCT_OFRNG TLSO LEFT JOIN TB_LMS_CRS_MSTR TLCM ON TLSO.SBJCT_REF_TYCD = 'CRS' AND TLSO.CRS_MSTR_ID = TLCM.CRS_MSTR_ID LEFT JOIN TB_LMS_SMSTR_CHRT TLSC ON TLSO.SBJCT_REF_TYCD = 'CHRT' AND TLSO.SMSTR_CHRT_ID = TLSC.SMSTR_CHRT_ID LEFT JOIN TB_LMS_ORG TLO ON TLO.ORG_ID = NVL(TLCM.ORG_ID, TLSC.ORG_ID) LEFT JOIN TB_LMS_DEPT TLD ON TLD.ORG_ID = TLO.ORG_ID WHERE 1=1
AND TLO.ORG_ID = #{orgId}
AND TLSO.DELYN = 'N' AND TLSO.USEYN = 'Y'
AND TLSC.DGRS_YR = #{creYear}
AND TLSC.DGRS_SMSTR_CHRT = #{creTerm}
AND TLD.DEPT_ID = #{deptId}
AND TLO.ORG_TYCD = #{uniCd}
AND TLSO.SBJCT_TYCD = #{crsTypeCd}
ORDER BY TLSO.SBJCTNM, TLSO.DVCLAS_NO
/* SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO --, A.UNIV_CD , A.DEPT_ID , A.SBJCT_TYCD , A.CRS_ID , A.UNIV_GBNCD FROM TB_LMS_SBJCT A, TB_LMS_CRS B WHERE 1=1 AND A.CRS_ID = B.CRS_ID
AND B.ORG_ID = #{orgId}
AND A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND A.DEPTCD = #{deptId}
AND A.UNIV_CD = #{uniCd}
AND A.SBJCT_TYCD = #{crsTypeCd}
ORDER BY A.SBJCTNM, A.DVCLAS_NO */

/* SQL ID : CrecrsDAO.selectStdCreCrsListTotCnt 설 명 : */ SELECT COUNT(1) AS TOT_CNT
, USER.PROF_TYCD FROM SBJCT_PROF USER,
FROM TB_LMS_ATNDLC_SBJCT USER,
(SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.SBJCT_ID , TLCC.DVCLAS_NO , TLCC.CMCRS_GBNCD , TLCC.CRDTS , (CASE WHEN TLC.SBJCT_TYCD = 'CO' THEN IF( DATE_FORMAT(NOW(),'%Y-%m-%d') BETWEEN DATE_FORMAT(TLCC.ATNDLC_SDTTM,'%Y-%m-%d') AND DATE_FORMAT(TLCC.ATNDLC_EDTTM ,'%Y-%m-%d') > 0, 'SERVICE', 'FINISH') WHEN TLC.SBJCT_TYCD = 'OPEN' THEN IF( TLCC.USEYN = 'Y', 'SERVICE', 'FINISH') WHEN TLC.SBJCT_TYCD = 'UNI' THEN ( SELECT TLT.SMSTR_STSCD FROM TB_LMS_TERM_CRE_CRS_RLTN TLTCCR, CRS_SMSTR TLT WHERE TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLCC.SBJCT_ID = TLTCCR.SBJCT_ID ) ELSE 'FINISH' END ) AS GUBUN , (CASE WHEN TLC.SBJCT_TYCD = 'UNI' THEN (SELECT F.SMSTR_TYCD FROM TB_LMS_TERM_CRE_CRS_RLTN E, CRS_SMSTR F WHERE E.CRS_SMSTR_ID = F.CRS_SMSTR_ID AND TLCC.SBJCT_ID = E.SBJCT_ID ) ELSE NULL END) AS TERMTYPE , TLC.SBJCT_TYCD , TLCC.SBJCT_OP_TYCD , (CASE WHEN TLC.SBJCT_TYCD = 'UNI' THEN '1' WHEN TLC.SBJCT_TYCD = 'CO' THEN '2' ELSE '3' END) AS SORT_ORDER , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = TLCC.SBJCT_ID AND ATNDLC_STSCD NOT IN ('D', 'E', 'N', 'T')) AS STD_TOTAL_CNT , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = TLCC.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = TLCC.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM FROM TB_LMS_SBJCT TLCC, TB_LMS_CRS TLC WHERE TLCC.CRS_ID = TLC.CRS_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y') CRETABLE WHERE USER.SBJCT_ID = CRETABLE.SBJCT_ID AND CRETABLE.GUBUN = #{termStatus}
AND CRETABLE.SBJCT_ID = #{crsYear}
AND USER.USER_ID = #{userId}
AND CRETABLE.SBJCT_TYCD = #{crsTypeCd}
AND CRETABLE.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_TERM_CRE_CRS_RLTN TLTCCR, CRS_SMSTR TLT WHERE TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND CRETABLE.SBJCT_ID = TLTCCR.SBJCT_ID
AND TLT.SMSTR_TYCD = #{termType}
AND TLT.CRS_SMSTR_ID = #{termCd}
)
AND ( LOWER(CRETABLE.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(CRETABLE.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(SELECT USERNM FROM USR WHERE USER_ID = USER.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY CRETABLE.SORT_ORDER ASC, CRETABLE.SBJCTNM ASC

/* SQL ID : CrecrsDAO.selectStdCreCrsList 설 명 : 마이페이지 > 수강, 강의 리스트 */ SELECT COUNT(*) OVER() AS TOTAL_CNT , CRETABLE.SBJCT_ID , CRETABLE.SBJCTNM , CRETABLE.GUBUN , CRETABLE.SBJCT_TYCD , CRETABLE.TERMTYPE , CRETABLE.DVCLAS_NO , CRETABLE.CMCRS_GBNCD , CRETABLE.CRDTS , CRETABLE.SBJCT_OP_TYCD , CRETABLE.STD_TOTAL_CNT , CRETABLE.USERNM
, USER.PROF_TYCD FROM SBJCT_PROF USER,
FROM TB_LMS_ATNDLC_SBJCT USER,
(SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.SBJCT_ID , TLCC.DVCLAS_NO , TLCC.CMCRS_GBNCD , TLCC.CRDTS , (CASE WHEN TLC.SBJCT_TYCD = 'CO' THEN IF( DATE_FORMAT(NOW(),'%Y-%m-%d') BETWEEN DATE_FORMAT(TLCC.ATNDLC_SDTTM,'%Y-%m-%d') AND DATE_FORMAT(TLCC.ATNDLC_EDTTM ,'%Y-%m-%d') > 0, 'SERVICE', 'FINISH') WHEN TLC.SBJCT_TYCD = 'OPEN' THEN IF( TLCC.USEYN = 'Y', 'SERVICE', 'FINISH') WHEN TLC.SBJCT_TYCD = 'UNI' THEN ( SELECT TLT.SMSTR_STSCD FROM TB_LMS_TERM_CRE_CRS_RLTN TLTCCR, CRS_SMSTR TLT WHERE TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLCC.SBJCT_ID = TLTCCR.SBJCT_ID ) ELSE 'FINISH' END ) AS GUBUN , (CASE WHEN TLC.SBJCT_TYCD = 'UNI' THEN (SELECT F.SMSTR_TYCD FROM TB_LMS_TERM_CRE_CRS_RLTN E, CRS_SMSTR F WHERE E.CRS_SMSTR_ID = F.CRS_SMSTR_ID AND TLCC.SBJCT_ID = E.SBJCT_ID ) ELSE NULL END) AS TERMTYPE , TLC.SBJCT_TYCD , TLCC.SBJCT_OP_TYCD , (CASE WHEN TLC.SBJCT_TYCD = 'UNI' THEN '1' WHEN TLC.SBJCT_TYCD = 'CO' THEN '2' ELSE '3' END) AS SORT_ORDER , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = TLCC.SBJCT_ID AND ATNDLC_STSCD NOT IN ('D', 'E', 'N', 'T')) AS STD_TOTAL_CNT , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = TLCC.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = TLCC.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM FROM TB_LMS_SBJCT TLCC, TB_LMS_CRS TLC WHERE TLCC.CRS_ID =TLC.CRS_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y') CRETABLE WHERE USER.SBJCT_ID = CRETABLE.SBJCT_ID AND CRETABLE.GUBUN = #{termStatus}
AND CRETABLE.SBJCT_ID = #{crsYear}
AND USER.USER_ID = #{userId}
AND CRETABLE.SBJCT_TYCD = #{crsTypeCd}
AND CRETABLE.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_TERM_CRE_CRS_RLTN TLTCCR, CRS_SMSTR TLT WHERE TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND CRETABLE.SBJCT_ID = TLTCCR.SBJCT_ID
AND TLT.SMSTR_TYCD = #{termType}
AND TLT.CRS_SMSTR_ID = #{termCd}
)
AND ( LOWER(CRETABLE.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(CRETABLE.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(SELECT USERNM FROM USR WHERE USER_ID = USER.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY CRETABLE.SORT_ORDER ASC, CRETABLE.SBJCTNM ASC LIMIT #{firstIndex}, #{listScale}

/* SQL ID : CrecrsDAO.listTchCrsCreByTerm 설 명 : 학기별 교수자의 개설과목 목록 */ SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO
FROM TB_LMS_SBJCT A
WHERE 1=1
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND B.CRS_SMSTR_ID = #{termCd}
AND A.DELYN = 'N' AND A.USEYN = 'Y' AND EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y'
AND USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = #{crsCreCd} AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')
AND USER_ID = #{userId}
)

	/*
		 SQL ID : CreCrsDAO.creCrsTchJoinList
		 설  명 : 과정 정보 가져오기 : 과정 단위에서 구성
 	*/
	SELECT  DISTINCT(A.SBJCT_ID) AS SBJCT_ID
			 ,	B.SBJCTNM
			 ,	B.CRS_ID
			 ,	B.DVCLAS_NO
	FROM SBJCT_PROF A
	INNER JOIN TB_LMS_SBJCT B
	ON A.SBJCT_ID = B.SBJCT_ID

		INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN  C
	  	ON B.SBJCT_ID = C.SBJCT_ID

	WHERE 1 = 1

		AND (A.USER_ID IN

			#{item}


			OR B.CRS_ID = #{crsCd}

		   )


		AND C.CRS_SMSTR_ID = #{termCd}


		AND B.SBJCT_ID = #{crsCreCd}

/* SQL ID : CreCrsDAO.listMainMypageStd 설 명 : 학생 > 메인 > 대시보드 과목 목록 */
SELECT X.*, LSC.LCTR_SCHDL_ID, LTI.SBJCT_LCTR_CLASTM_ID FROM ( SELECT CRE.SBJCT_ID , CRE.SBJCTNM , CRE.SBJCT_ENNM , CRE.SBJCT_TYCD , TERM.SMSTR_TYCD , CRE.SBJCT_OP_TYCD , CRE.DVCLAS_NO , CRE.CMCRS_GBNCD , CRE.UNIV_CD , CRE.UNIV_GBNCD , TERM.CRS_SMSTR_ID , (CASE WHEN CRE.SBJCT_TYCD != 'UNI' THEN CASE WHEN TO_CHAR(SYSDATE, 'YYYY.MM.DD') BETWEEN TO_CHAR(CRE.ATNDLC_SDTTM, 'YYYY.MM.DD') AND TO_CHAR(CRE.ATNDLC_EDTTM, 'YYYY.MM.DD') THEN 'SERVICE' ELSE 'FINISH' END WHEN CRE.SBJCT_TYCD = 'UNI' THEN TERM.SMSTR_STSCD ELSE 'FINSH' END) AS GUBUN , (CASE WHEN CRE.SBJCT_TYCD = 'UNI' THEN '1' WHEN CRE.SBJCT_TYCD = 'CO' THEN '2' ELSE '3' END) AS SORT_ORDER , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = CRE.SBJCT_ID AND ATNDLC_STSCD = 'S') AS STD_CNT , CRE.CRS_ID , CRE.GRDTN_SBJCTYN , STD.AUDITYN , STD.REATNDLCYN , STD.ATNDLC_ABNDYN , STD.PRRQST_SBJCT_ATNDLCYN , STD.SPPLMNT_SBJCTYN , NVL(CRE.TMSW_PRRQST_SBJCTYN,'N') TMSW_PRRQST_SBJCTYN , NVL(CRE.TMSW_PRRQST_SBJCT_BFRYN,'N') TMSW_PRRQST_SBJCT_BFRYN , CRE.ATNDLC_SDTTM , CRE.ATNDLC_EDTTM
FROM TB_LMS_SBJCT CRE JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON CRE.SBJCT_ID = B.SBJCT_ID JOIN CRS_SMSTR TERM ON B.CRS_SMSTR_ID = TERM.CRS_SMSTR_ID JOIN TB_LMS_ATNDLC_SBJCT STD ON CRE.SBJCT_ID = STD.SBJCT_ID AND STD.ATNDLC_STSCD = 'S' AND STD.USER_ID = #{userId} WHERE CRE.DELYN = 'N' AND CRE.USEYN = 'Y'
AND CRE.SBJCT_TYCD = #{crsTypeCd}
AND TERM.SMSTR_TYCD = #{termType}
AND TO_DATE(CRE.ATNDLC_SDTTM, 'YYYYMMDDHH24MISS') < SYSDATE AND TO_DATE(CRE.ATNDLC_EDTTM, 'YYYYMMDDHH24MISS') > SYSDATE
AND TERM.CRS_SMSTR_ID = #{termCd}
) X LEFT JOIN ( SELECT SBJCT_ID, LCTR_SCHDL_ID FROM ( SELECT SBJCT_ID, LCTR_SCHDL_ID, ROW_NUMBER() OVER (PARTITION BY SBJCT_ID ORDER BY LCTR_SCHDL_SEQ) AS RN FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE DELYN = 'N' AND LCTR_SCHDL_SEQ = 1 ) WHERE RN = 1 ) LSC ON X.SBJCT_ID = LSC.SBJCT_ID LEFT JOIN ( SELECT SBJCT_ID, SBJCT_LCTR_CLASTM_ID FROM ( SELECT AA.SBJCT_ID, AA.SBJCT_LCTR_CLASTM_ID, ROW_NUMBER() OVER (PARTITION BY AA.SBJCT_ID ORDER BY AA.LCTR_CLASTM_SEQ) AS RN FROM TB_LMS_SBJCT_LCTR_CLASTM AA JOIN TB_LMS_SBJCT_LCTR_SCHDL BB ON AA.LCTR_SCHDL_ID = BB.LCTR_SCHDL_ID AND BB.LCTR_SCHDL_SEQ = 1 AND BB.DELYN = 'N' ) WHERE RN = 1 ) LTI ON X.SBJCT_ID = LTI.SBJCT_ID
WHERE 1 = 1 AND X.GUBUN = #{termStatus}
ORDER BY X.SORT_ORDER ASC, X.SBJCTNM ASC

/* SQL ID : CreCrsDAO.listMainMypageTch 설 명 : 교수 > 마이페이지 리스트 */ SELECT TLCM.ORG_ID , TLSO.SBJCT_ID , TLSO.SBJCTNM , TLSO.SBJCT_ENNM , TLSO.SBJCT_TYCD , TLSO.DVCLAS_NO , TLSO.CMCRS_GBNCD , TLSO.ATNDLC_SDTTM , TLSO.ATNDLC_EDTTM FROM TB_LMS_SBJCT TLSO , TB_LMS_CRS_MSTR TLCM WHERE TLSO.CRS_MSTR_ID = TLCM.CRS_MSTR_ID AND TLSO.DELYN = 'N' AND TLSO.USEYN = 'Y' AND TLSO.PROF_ID = #{userId}
AND TLSO.SBJCT_TYCD = #{crsTypeCd}
AND TLSO.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_TERM_CRE_CRS_RLTN TLTCCR, CRS_SMSTR TLT WHERE TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND CRETABLE.SBJCT_ID = TLTCCR.SBJCT_ID
AND TLT.SMSTR_TYCD = #{termType}
AND TLT.CRS_SMSTR_ID = #{termCd}
AND TLT.DGRS_YR = #{haksaYear}
AND TLT.DGRS_SMSTR = #{haksaTerm}
)

/* SQL ID : CreCrsDAO.creMypageTchList 설 명 : 교수 > 마이페이지 리스트 */
SELECT ROW_NUMBER() OVER(ORDER BY B.SBJCTNM, B.DEPT_ID, B.DVCLAS_NO ASC) AS LINE_NO , B.SBJCT_ID , B.CRS_ID , B.SBJCT_ID , B.CRS_ID , B.SBJCT_OP_TYCD , B.DVCLAS_NO , B.SBJCTNM , B.SBJCT_ENNM , B.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE DEPT_ID = B.DEPT_ID AND USEYN = 'Y') AS DEPTNM , A.PROF_TYCD
, B.CMCRS_GBNCD , B.LCTR_TYCD , B.LRN_CNTRL , B.USEYN , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM , (CASE WHEN (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y') IS NULL THEN '-' ELSE (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y') END) AS USER_ID
, (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE B.CRS_ID = CRS_ID) AS SBJCT_TYCD , (CASE WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE B.CRS_ID = CRS_ID ) = 'UNI' THEN (SELECT F.SMSTR_TYCD FROM TB_LMS_TERM_CRE_CRS_RLTN E, CRS_SMSTR F WHERE E.CRS_SMSTR_ID = F.CRS_SMSTR_ID AND A.SBJCT_ID = E.SBJCT_ID AND F.SMSTR_STSCD = 'service') ELSE NULL END) AS SMSTR_TYCD , (CASE WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE B.CRS_ID = CRS_ID) = 'UNI' THEN '1' WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE B.CRS_ID = CRS_ID) = 'CO' THEN '2' ELSE '3' END) AS SORT_ORDER
, (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = B.SBJCT_ID) AS STD_TOTAL_CNT FROM SBJCT_PROF A INNER JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND A.USER_ID = #{userId}
INNER JOIN TB_LMS_CRS G ON B.CRS_ID = G.CRS_ID AND G.SBJCT_TYCD = #{crsTypeCd}
AND A.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_TERM_CRE_CRS_RLTN C, CRS_SMSTR D WHERE C.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND A.SBJCT_ID = C.SBJCT_ID
AND D.SMSTR_TYCD = #{termType}
AND D.CRS_SMSTR_ID = #{termCd}
)
WHERE 1 = 1
AND B.SBJCTNM LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY B.SBJCTNM, B.DEPT_ID, B.DVCLAS_NO

/* SQL ID : CreCrsDAO.creMypageStdList 설 명 : 학생 > 마이페이지 리스트 */
SELECT ROW_NUMBER() OVER (ORDER BY SBJCTNM DESC) AS LINE_NO , A.SBJCT_ID , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , A.DVCLAS_NO , A.SBJCTNM , A.SBJCT_ENNM , A.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE DEPT_ID = A.DEPT_ID AND USEYN = 'Y') AS DEPTNM
, A.CMCRS_GBNCD , A.LCTR_TYCD , A.LRN_CNTRL , A.USEYN , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM , (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID) AS SBJCT_TYCD , (CASE WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID ) = 'UNI' THEN (SELECT F.SMSTR_TYCD FROM TB_LMS_TERM_CRE_CRS_RLTN E, CRS_SMSTR F WHERE E.CRS_SMSTR_ID = F.CRS_SMSTR_ID AND A.SBJCT_ID = E.SBJCT_ID AND F.SMSTR_STSCD = 'SERVICE') ELSE NULL END) AS SMSTR_TYCD , (CASE WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID) = 'UNI' THEN '1' WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID) = 'CO' THEN '2' ELSE '3' END) AS SORT_ORDER
, (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS STD_TOTAL_CNT FROM TB_LMS_SBJCT A INNER JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND A.USEYN = 'Y' AND A.DELYN = 'N' AND B.USER_ID = #{userId}
INNER JOIN TB_LMS_CRS G ON A.CRS_ID = G.CRS_ID AND G.SBJCT_TYCD = #{crsTypeCd}
AND B.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_TERM_CRE_CRS_RLTN C, CRS_SMSTR D WHERE C.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND A.SBJCT_ID = C.SBJCT_ID
AND D.SMSTR_TYCD = #{termType}
AND D.CRS_SMSTR_ID = #{termCd}
)
WHERE 1 = 1
AND B.SBJCTNM LIKE FN_LIKE_VAL(#{searchValue})
ORDER BY A.SBJCTNM, A.DEPT_ID, A.DVCLAS_NO

/* SQL ID : CreCrsDAO.listCrecrsTch 설 명 : 과목 > 조교/교수 목록 */ SELECT A.SBJCT_ID , A.USER_ID , A.PROF_TYCD , A.RPRSYN , A.AIS_DATA_LNKGYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = A.USER_ID) END) AS USERNM , (SELECT EMAIL FROM USR WHERE USER_ID = A.USER_ID) AS EMAIL , (SELECT MOBILE_NO FROM USR WHERE USER_ID = A.USER_ID) AS MOBILE_NO , (SELECT OFCE_TELNO FROM USR WHERE USER_ID = A.USER_ID) AS OFCE_TEL_NO , (SELECT PHT_FILE FROM USR WHERE USER_ID = A.USER_ID) AS PHT_FILE_BYTE FROM SBJCT_PROF A WHERE 1=1
AND A.SBJCT_ID IN
#{item}
AND A.SBJCT_ID = #{crsCreCd}
AND A.PROF_TYCD != 'ASSISTANT'
AND A.PROF_TYCD = 'ASSISTANT'
AND A.PROF_TYCD != 'MONITORING' ORDER BY A.PROF_TYCD DESC

/* SQL ID : CreCrsDAO.listCrecrsTchByMenuType 설 명 : 사용자와 동일 학과 교수 목록 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY A.USER_ID) AS LINE_NO , A.DEPTNM , A.USER_ID , A.USERNM , B.MENU_TYCD , COUNT(1) OVER() AS TOTAL_CNT FROM USR A INNER JOIN TB_LMS_USER_AUTHRT B ON A.USER_ID = B.USER_ID INNER JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID AND C.ACNT_STSCD != 'D' WHERE A.DEPT_ID = (SELECT DEPT_ID FROM USR WHERE USER_ID = #{userId}) AND (B.MENU_TYCD = 'PROFESSOR' OR B.USER_AUTHRT_ID = 'TUT') AND NOT EXISTS ( SELECT 1 FROM SBJCT_PROF WHERE SBJCT_ID = #{crsCreCd} AND USER_ID = A.USER_ID )
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

mapper.insert:
