 	*/
 	DELETE FROM SBJCT_PROF
 	 WHERE SBJCT_ID = #{crsCreCd}

 	   AND USER_ID = #{userId}


 	   AND PROF_TYCD = #{tchType}

mapper.select:
/* SQL ID : CreCrsDAO.listCrecrsByUserDept 설 명 : 사용자와 동일 학과 과목 목록 페이징 */ SELECT ROW_NUMBER() OVER(ORDER BY (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE ORG_ID = #{orgId} AND DEPT_ID = A.DEPT_ID), A.SBJCTNM) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , A.SBJCT_ID , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'SBJCT_TYCD' AND CD = A.SBJCT_TYCD) AS CRS_TYPE_NM , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'LEARNING_TYPE' AND CD = A.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , A.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE ORG_ID = #{orgId} AND DEPT_ID = A.DEPT_ID) AS DEPTNM , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , (SELECT USERNM FROM USR WHERE USER_ID = B.USER_ID) AS TCH_NM , ( SELECT GROUP_CONCAT((SELECT USERNM FROM USR WHERE USER_ID = AA.USER_ID)) FROM SBJCT_PROF AA WHERE AA.SBJCT_ID = A.SBJCT_ID AND AA.PROF_TYCD = 'ASSISTANT' ) TUTOR_NM , IFNULL((SELECT 'Y' FROM SBJCT_PROF WHERE USER_ID = #{userId} AND SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'MONITORING'), 'N') AS MONITORING_YN FROM TB_LMS_SBJCT A LEFT JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD = 'PROFESSOR' AND B.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.DEPT_ID IN (
SELECT AA.DEPT_ID FROM USR AA WHERE AA.USER_ID = #{userId} UNION ALL SELECT CC.DEPT_ID FROM USR AA JOIN TB_HOME_USER_DEPT_ID BB ON AA.DEPT_ID = BB.DEPT_ID AND BB.ORG_ID = #{orgId} AND BB.PAR_DEPT_ID = '10000' AND BB.USEYN = 'Y' JOIN TB_HOME_USER_DEPT_ID CC ON BB.DEPT_ID = CC.PAR_DEPT_ID AND CC.ORG_ID = #{orgId} AND CC.USEYN = 'Y' WHERE AA.USER_ID = #{userId}
SELECT AA.DEPT_ID FROM TB_HOME_USER_MGNT_DEPT AA JOIN TB_HOME_USER_DEPT_ID BB ON AA.DEPT_ID = BB.DEPT_ID AND BB.ORG_ID = #{orgId} WHERE AA.USER_ID = #{userId} AND AA.MSTYN = 'Y' UNION ALL SELECT CC.DEPT_ID FROM TB_HOME_USER_MGNT_DEPT AA JOIN TB_HOME_USER_DEPT_ID BB ON AA.DEPT_ID = BB.DEPT_ID AND BB.ORG_ID = #{orgId} AND BB.PAR_DEPT_ID = '10000' AND BB.USEYN = 'Y' JOIN TB_HOME_USER_DEPT_ID CC ON BB.DEPT_ID = CC.PAR_DEPT_ID AND CC.ORG_ID = #{orgId} AND CC.USEYN = 'Y' WHERE AA.USER_ID = #{userId} AND AA.MSTYN = 'Y'
) AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm} AND A.SBJCT_ID NOT IN ( SELECT SBJCT_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND USER_ID = #{userId} AND PROF_TYCD != 'MONITORING' )
AND ( LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = B.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
LIMIT #{firstIndex}, #{listScale}

/* SQL ID : CreCrsDAO.listUserCreCrsPaging 설 명 : 사용자 관리 > 사용자 상세 강의(수강) 과목 리스트 */ SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.SORT_ORDER DESC, A.SBJCTNM DESC, A.DVCLAS_NO DESC) AS LINE_NO , A.* FROM (SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.CRS_ID , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'CMCRS_GBNCD' AND CD = A.CMCRS_GBNCD) AS COMP_DV_NM , A.CRDTS , (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_CONTS WHERE SBJCT_ID = A.SBJCT_ID) AS LESSON_CNT , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'LEARNING_TYPE' AND CD = A.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S') AS STD_CNT , (CASE WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID) = 'UNI' THEN '1' WHEN (SELECT SBJCT_TYCD FROM TB_LMS_CRS WHERE A.CRS_ID = CRS_ID) = 'CO' THEN '2' ELSE '3' END ) AS SORT_ORDER , COUNT(1) OVER() AS TOTAL_CNT FROM TB_LMS_SBJCT A
JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND A.DELYN = 'N' AND A.USEYN = 'Y' AND B.USER_ID = #{userId} JOIN TB_LMS_TERM_CRE_CRS_RLTN TRLTN ON A.SBJCT_ID = TRLTN.SBJCT_ID
JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND A.DELYN = 'N' AND A.USEYN = 'Y' AND B.ATNDLC_STSCD = 'S' AND B.USER_ID = #{userId}
JOIN TB_LMS_CRS G ON A.CRS_ID = G.CRS_ID AND G.SBJCT_TYCD = #{crsTypeCd}
JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID AND C.CRS_SMSTR_ID = #{termCd}
WHERE A.CRS_ID IN (SELECT CRS_ID FROM TB_LMS_CRS WHERE ORG_ID = #{orgId})
) A ) WHERE 1=1
AND LINE_NO BETWEEN #{firstIndex} AND #{listScale}
ORDER BY SORT_ORDER, SBJCTNM, DVCLAS_NO

/* SQL ID : CreCrsDAO.listCreCrs 설 명 : 교수/조교 관리 > 개설과목 리스트 */ WITH SBJ_LIST AS ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , SMSTR.ORG_ID , A.DEPT_ID , A.SBJCT_OFRNG_ID , A.SBJCTNM , A.PROF_ID FROM TB_LMS_SBJCT_OFRNG A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID LEFT JOIN TB_LMS_DEPT DEPT ON A.DEPT_ID = DEPT.DEPT_ID AND SMSTR.ORG_ID = DEPT.ORG_ID WHERE 1=1 AND A.DELYN = 'N' UNION ALL SELECT A.SBJCT_YR , A.SBJCT_SMSTR , CRS.ORG_ID , '-' , '-' , A.SBJCT_OFRNG_ID , A.SBJCTNM , A.PROF_ID FROM TB_LMS_SBJCT_OFRNG A JOIN TB_LMS_CRS_MSTR CRS ON A.SBJCT_REF_TYCD = 'CRS_MSTR' AND A.CRS_MSTR_ID = CRS.CRS_MSTR_ID WHERE 1=1 AND A.DELYN = 'N' ) SELECT A.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY SBJ.SBJCT_YR ASC, SBJ.SBJCT_SMSTR ASC, SBJ.DEPTNM DESC, SBJ.SBJCTNM DESC) AS LINE_NO , SBJ.*
FROM SBJ_LIST SBJ WHERE 1=1
AND SBJ.SBJCT_YR = #{sbjctYr}
AND SBJ.SBJCT_SMSTR = #{sbjctSmstr}
AND SBJ.ORG_ID = #{orgId}
AND SBJ.DEPT_ID = #{deptId}
AND SBJ.SBJCT_OFRNG_ID = #{sbjctOfrngId}
AND SBJ.PROF_ID = #{userId}
) A WHERE 1 = 1
AND ( OR LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.PROF_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.LINE_NO DESC

/* SQL ID : CreCrsDAO.listTchStatus 설 명 : 교수/조교 정보 > 교수/조교 목록 */
WITH CRE_CRS_T AS ( SELECT A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , A.DEPT_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND A.SBJCT_TYCD IN
#{item}
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{crsCreCd}
)
SELECT ROW_NUMBER() OVER(ORDER BY A.CRS_ID, A.SBJCTNM, A.DVCLAS_NO) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE ORG_ID = #{orgId} AND CD = A.DEPT_ID) AS DEPTNM , B.PROFESSOR_NO , B.PROFESSOR_NM , B.ASSOCIATE_NO , B.ASSOCIATE_NM , B.TUTOR_NO , B.TUTOR_NM FROM TB_LMS_SBJCT A LEFT JOIN ( SELECT A.SBJCT_ID , MAX(A.PROFESSOR_NO) AS PROFESSOR_NO , MAX(A.PROFESSOR_NM) AS PROFESSOR_NM , MAX(A.ASSOCIATE_NO) AS ASSOCIATE_NO , MAX(A.ASSOCIATE_NM) AS ASSOCIATE_NM , MAX(A.TUTOR_NO) AS TUTOR_NO , MAX(A.TUTOR_NM) AS TUTOR_NM FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.SBJCT_ID, A.PROF_TYCD, A.RPRSYN ORDER BY A.REG_DTTM) AS RN , A.SBJCT_ID , A.PROF_TYCD , A.RPRSYN , CASE WHEN A.PROF_TYCD = 'PROFESSOR' AND A.RPRSYN = 'Y' THEN B.USER_PRFIL_ID ELSE NULL END AS PROFESSOR_NO , CASE WHEN A.PROF_TYCD = 'PROFESSOR' AND A.RPRSYN = 'Y' THEN B.USERNM ELSE NULL END AS PROFESSOR_NM , CASE WHEN A.PROF_TYCD = 'PROFESSOR' AND A.RPRSYN = 'N' THEN B.USER_PRFIL_ID ELSE NULL END AS ASSOCIATE_NO , CASE WHEN A.PROF_TYCD = 'PROFESSOR' AND A.RPRSYN = 'N' THEN B.USERNM ELSE NULL END AS ASSOCIATE_NM , CASE WHEN A.PROF_TYCD = 'ASSISTANT' THEN B.USER_PRFIL_ID ELSE NULL END AS TUTOR_NO , CASE WHEN A.PROF_TYCD = 'ASSISTANT' THEN B.USERNM ELSE NULL END AS TUTOR_NM FROM TB_LMS_SBJCT_PROF A JOIN TB_LMS_USER_PRFIL B ON A.USER_ID = B.USER_PRFIL_ID AND B.ORG_ID = #{orgId} JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID AND C.USER_ID_STSCD = 'U' WHERE A.SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_SBJCT) ) A WHERE RN = 1 GROUP BY A.SBJCT_ID ) B ON A.SBJCT_ID = B.SBJCT_ID WHERE 1=1
AND ( LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.PROFESSOR_NM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.ASSOCIATE_NM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.TUTOR_NM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.CRS_ID, A.SBJCTNM, A.DVCLAS_NO

/* SQL ID : CreCrsDAO.crsCreTopInfo 설 명 : 강의실 상단 정보 */ SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE ORG_ID = B.ORG_ID AND DEPT_ID = A.DEPT_ID AND USEYN = 'Y') AS DEPTNM , A.CMCRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'CMCRS_GBNCD' AND CD = A.CMCRS_GBNCD) AS COMP_DV_NM FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID
AND B.ORG_ID = #{orgId}
WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd}

/* SQL ID : CreCrsDAO.selectListPage 설 명 : 개설과목 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_ID) AS LINE_NO , COUNT(A.SBJCT_ID) OVER() AS TOTAL_CNT , C.CRS_SMSTR_ID , (SELECT SMSTRNM FROM CRS_SMSTR WHERE CRS_SMSTR_ID = C.CRS_SMSTR_ID) AS SMSTRNM , A.SBJCT_ID , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , A.DVCLAS_NO , A.SBJCTNM , A.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE ORG_ID = #{orgId} AND DEPT_ID = A.DEPT_ID AND USEYN = 'Y') AS DEPTNM , A.SBJCT_ENNM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_CERT_STSCD , A.ATNDLC_APLY_MTHD_CD , A.QUOTA_LMTYN , A.ATNDLC_QUOTA , A.DPLM_OTPTYN , A.DPLM_SCRYN , A.FNSH_SCR , A.CRDTS , A.MID_ATNDC_CHK_USEYN , A.AIS_DATA_LNKGYN , A.MRK_OYN , A.CMCRS_GBNCD , A.MRK_PROC_SDTTM , A.MRK_PROC_EDTTM , A.MRK_OPEN_SDTTM , A.LCTR_TYCD , A.LRN_CNTRL , A.USEYN , A.KYWD , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , B.MRK_GRD_TYCD , B.MRK_EVL_TYCD , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD NOT IN('D', 'T')) AS STD_TOTAL_CNT , (SELECT COUNT(*) FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID) AS TCH_TOTAL_CNT , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM , (CASE WHEN (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USER_ID , A.UNIV_CD FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_CRE_CRS_EVAL B ON A.SBJCT_ID = B.SBJCT_ID INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID WHERE 1 = 1 AND A.CRS_ID IN (SELECT CRS_ID FROM TB_LMS_CRS WHERE SBJCT_TYCD = #{crsTypeCd})
AND C.CRS_SMSTR_ID = #{termCd}
AND ( LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y'))) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.SBJCT_ID DESC

mapper.insert:
		/*
			 SQL ID : CreCrsDAO.insert
			 설  명 : 과목 정보 등록
	 	*/
		INSERT INTO TB_LMS_SBJCT (
               SBJCT_ID
             , CRS_ID
