		     , ATNDLC_APLY_SDTTM
		     , ATNDLC_APLY_EDTTM
		     , ATNDLC_SDTTM
		     , ATNDLC_EDTTM
		     , AUDIT_EDTTM
		     , ATNDLC_CERT_STSCD
		     , ATNDLC_APLY_MTHD_CD
		     , QUOTA_LMTYN
		     , ATNDLC_QUOTA
		     , DPLM_OTPTYN
		     , DPLM_SCRYN
