/* SQL ID : CreCrsDAO.checkDeclsNo 설 명 : 분반 중복체크 */
SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.DVCLAS_NO , TLTCCR.CRS_SMSTR_ID FROM TB_LMS_SBJCT TLCC, TB_LMS_TERM_CRE_CRS_RLTN TLTCCR WHERE TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLTCCR.CRS_SMSTR_ID = #{termCd} AND TLCC.CRS_ID = #{crsCd} AND TLCC.DVCLAS_NO = #{declsNo} AND TLCC.DELYN = 'N'
SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.CRS_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.CRS_SMSTR_ID = #{termCd} WHERE A.DELYN = 'N' AND A.CRS_ID = #{crsCd} AND A.DVCLAS_NO = #{declsNo}

		/*
			 SQL ID :  CreCrsDAO.checkDeclsCnt
