	 	*/


		SELECT COUNT(1)
		FROM TB_LMS_SBJCT
		WHERE SBJCT_YR = #{creYear}
          AND SBJCT_SMSTR = #{creTerm}
		  AND DELYN = 'N'
		  AND CRS_ID = #{crsCd}
		  AND DVCLAS_NO = #{declsNo}

/* SQL ID : CreCrsDAO.selectListCreTch 설 명 : 개설과목관리 > 등록된 운영자 리스트 */ SELECT X.* , ROW_NUMBER() OVER(ORDER BY CNT, USER_ID, USERNM) AS LINE_NO FROM ( SELECT A.SBJCT_ID , A.USER_ID , (SELECT USERNM FROM USR WHERE USER_ID = A.USER_ID) AS USERNM , (SELECT DEPTNM FROM USR WHERE USER_ID = A.USER_ID) AS DEPTNM , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) AS USER_ID , A.PROF_TYCD , (SELECT X.CDNM FROM TB_ORG_CODE X WHERE X.ORG_ID = #{orgId} AND X.CTGRCD = 'CRE_TCH_TYPE' AND X.CD = A.PROF_TYCD) AS TCH_TYPE_NM , (CASE WHEN PROF_TYCD = 'PROFESSOR' THEN 1 WHEN PROF_TYCD = 'ASSOCIATE' THEN 2 ELSE 3 END ) AS CNT , A.RPRSYN , A.AIS_DATA_LNKGYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM SBJCT_PROF A WHERE 1 = 1 AND A.SBJCT_ID = #{crsCreCd}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT DEPTNM FROM USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.SBJCT_ID IN (SELECT B.SBJCT_ID FROM TB_LMS_SBJCT B WHERE B.CRS_ID = #{crsCd})
) X

