mapper.select:
/* SQL ID : CreCrsDAO.selectUsrTchList 설 명 : 교수자의 페이징 목록 */ SELECT ROW_NUMBER() OVER ( ORDER BY B.USER_ID ASC ORDER BY B.USER_ID DESC ORDER BY A.USERNM ASC ORDER BY A.USERNM DESC ORDER BY A.MOBILE_NO ASC ORDER BY A.MOBILE_NO DESC ORDER BY A.EMAIL ASC ORDER BY A.EMAIL DESC ORDER BY B.FRST_INQ_DTTM ASC ORDER BY B.FRST_INQ_DTTM DESC ORDER BY B.ACNT_STSCD ASC ORDER BY B.ACNT_STSCD DESC ORDER BY B.USER_ID ASC ) AS LINE_NO , A.USER_ID , A.USERNM , A.USER_ENNM , IFNULL(A.PRFIL_PHOTO_FILE_ID,0) AS PRFIL_PHOTO_FILE_ID , A.DUP_INFO , A.MOBILE_NO , A.EMAIL , A.ORG_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , A.DEPT_ID , (SELECT DEPTNM FROM USR WHERE USER_ID = A.USER_ID) AS DEPTNM , A.EMAIL_RECV , A.SMS_RECV , A.DISABLILITY_YN , A.USER_GRADE , B.USER_ID , B.USER_ENCPSWD , B.ADMIN_LOGIN_ACPT_DIV_CD , B.LOGIN_FAIL_DTTM , B.LGN_CNTNU_FAIL_CNT , B.LAST_LOGIN_DTTM , B.LOGIN_CNT , B.ACNT_LEAVE_DTTM , B.ACNT_STSCD , B.RGTR_ID , B.FRST_INQ_DTTM , B.MDFR_ID , B.MOD_DTTM , B.SNS_GBNCD , B.SNS_KEY , (SELECT MENU_TYCD FROM TB_LMS_USER_AUTHRT WHERE USER_ID = A.USER_ID ORDER BY MENU_TYCD DESC LIMIT 1) AS ADMIN_AUTH_GRP_CD , (SELECT USER_AUTHRT_ID FROM TB_LMS_USER_AUTHRT WHERE USER_ID = A.USER_ID ORDER BY MENU_TYCD DESC LIMIT 1) AS WWW_AUTH_GRP_CD , (SELECT GROUP_CONCAT(SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'USER_TYPE' AND CD = USER_AUTHRT_ID) FROM TB_LMS_USER_AUTHRT WHERE USER_ID = TLLAH.RGTR_ID) AS AUTHRT_GRPNM , COUNT(1) OVER() AS TOTAL_CNT FROM USR A, TB_LMS_USER_ACNT B WHERE A.USER_ID = B.USER_ID
AND A.ORG_ID IS NOT NULL AND EXISTS ( SELECT USER_ID FROM TB_LMS_USER_AUTHRT WHERE MENU_TYCD = #{searchAuthGrp} AND USER_ID = A.USER_ID )
AND A.ORG_ID = #{orgId}
AND ( LOWER(B.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND B.ACNT_STSCD = #{userSts}
ORDER BY B.USER_ID ASC ORDER BY B.USER_ID DESC ORDER BY A.USERNM ASC ORDER BY A.USERNM DESC ORDER BY A.MOBILE_NO ASC ORDER BY A.MOBILE_NO DESC ORDER BY A.EMAIL ASC ORDER BY A.EMAIL DESC ORDER BY B.FRST_INQ_DTTM ASC ORDER BY B.FRST_INQ_DTTM DESC ORDER BY B.ACNT_STSCD ASC ORDER BY B.ACNT_STSCD DESC ORDER BY B.USER_ID DESC

