mapper.select:
/* SQL ID : CreCrsDAO.coListPageing 설 명 : 개설과목 페이징 (기수제) */
SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_ID) AS LINE_NO , A.SBJCT_ID , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , (SELECT C.CRS_CTGRNM FROM TB_LMS_CRS_CTGR C WHERE C.CRS_CTGRCD = B.CRS_CTGRCD) AS CRS_CTGRNM , (SELECT C.CRS_CTGRCD FROM TB_LMS_CRS_CTGR C WHERE C.CRS_CTGRCD = B.CRS_CTGRCD) AS CRS_CTGRCD , (SELECT D.THM_ID FROM TB_LMS_CRE_TM_CTGR D WHERE D.THM_ID = B.CRS_CTGRCD) AS CRE_TM_CTGR_NM , (SELECT D.THM_ID FROM TB_LMS_CRE_TM_CTGR D WHERE D.THM_ID = B.CRS_CTGRCD) AS THM_ID , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , A.DVCLAS_NO , A.SBJCTNM , A.DEPT_ID , A.SBJCT_ENNM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_CERT_STSCD , A.ATNDLC_APLY_MTHD_CD , IFNULL(A.QUOTA_LMTYN,'N') AS QUOTA_LMTYN , A.ATNDLC_QUOTA , A.DPLM_OTPTYN , A.DPLM_SCRYN , A.FNSH_SCR , A.CRDTS , A.MID_ATNDC_CHK_USEYN , A.AIS_DATA_LNKGYN , A.MRK_OYN , A.CMCRS_GBNCD , A.MRK_PROC_SDTTM , A.MRK_PROC_EDTTM , A.MRK_OPEN_SDTTM , A.LCTR_TYCD , A.LRN_CNTRL , A.USEYN , A.KYWD , A.RGTR_ID , (SELECT USERNM FROM USR WHERE USER_ID = A.RGTR_ID) AS RGTRNM , A.FRST_INQ_DTTM , A.MDFR_ID , (SELECT USERNM FROM USR WHERE USER_ID = A.MDFR_ID) AS MOD_NM , A.MOD_DTTM , (SELECT COUNT(*) FROM TB_LMS_SBJCT WHERE CRS_ID = A.CRS_ID AND SBJCT_ID = IFNULL(#{crsYear}, SBJCT_ID)) AS CRE_CRS_CNT , B.ENRL_CERT_MTHD , B.SBJCT_TYCD , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD NOT IN ('D', 'E', 'N', 'T') ) AS STD_TOTAL_CNT , (SELECT COUNT(*) FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID) AS TCH_TOTAL_CNT , (CASE WHEN (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = D.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = D.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USERNM , (CASE WHEN (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = D.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) IS NULL THEN '-' ELSE (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = D.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')) END) AS USER_ID FROM TB_LMS_SBJCT A INNER JOIN TB_LMS_CRS B ON a.CRS_ID = b.CRS_ID WHERE 1 = 1 AND A.DELYN = 'N' AND B.SBJCT_TYCD = #{crsTypeCd}
AND LOWER(A.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{crsYear}))
AND B.CRS_CTGRCD = (SELECT CRS_CTGRCD FROM TB_LMS_CRS_CTGR D WHERE D.CRS_CTGRCD = B.CRS_CTGRCD AND D.CRS_CTGRCD = #{crsCtgrCd} )
AND LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY SBJCT_ID DESC

mapper.update:
	/*
		 SQL ID : CreCrsDAO.updateUseYn
		 설  명 : 개설 과목 목록(기수제) > 사용여부 변경
 	*/

		UPDATE TB_LMS_SBJCT
	 	   SET USEYN  = #{useYn}
		     , MDFR_ID  = #{mdfrId}
		     , MOD_DTTM  = FN_DTTM()
