mapper.select:
/* SQL ID : listCreTch 설 명 : 개설과목관리 > 등록된 운영자 리스트 */ SELECT ROW_NUMBER() OVER(ORDER BY A.USER_ID, A.RPRSYN) AS LINE_NO , A.SBJCT_ID , A.USER_ID AS USER_ID , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = A.USER_ID) AS USERNM , (SELECT '부서명' FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = A.USER_ID) AS DEPTNM , A.USER_ID , A.PROF_TYCD , (CASE WHEN PROF_TYCD = 'PROFESSOR' THEN 1 WHEN PROF_TYCD = 'ASSOCIATE' THEN 2 ELSE 3 END) AS CNT , A.RPRSYN , A.AIS_DATA_LNKGYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SBJCT_PROF A WHERE 1 = 1 AND A.SBJCT_ID = #{crsCreCd}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT DEPTNM FROM USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.SBJCT_ID IN (SELECT B.SBJCT_ID FROM TB_LMS_SBJCT B WHERE B.CRS_ID = #{crsCd})
ORDER BY A.USER_ID, A.RPRSYN

/* SQL ID : CreCrsDAO.countUni 설 명 : 개설 과목 전체 카운트 (대학) */
SELECT COUNT(*) FROM (SELECT ROW_NUMBER() OVER(ORDER BY SBJCTNM ASC) AS LINE_NO FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_CRE_CRS_EVAL B ON A.SBJCT_ID = B.SBJCT_ID INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID WHERE 1 = 1 AND A.DELYN = 'N' AND A.CRS_ID IN (SELECT CRS_ID FROM TB_LMS_CRS WHERE SBJCT_TYCD = 'UNI')
AND C.CRS_SMSTR_ID = #{termCd}
AND A.SBJCT_OP_TYCD = #{crsOperTypeCd}
AND ( LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y'))) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) T

/* SQL ID : CreCrsDAO.listPageing 설 명 : 개설과목 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY SBJCT_ID) AS LINE_NO , R.* FROM ( SELECT C.CRS_SMSTR_ID , (SELECT SMSTRNM FROM CRS_SMSTR WHERE CRS_SMSTR_ID = C.CRS_SMSTR_ID) AS SMSTRNM , A.SBJCT_ID , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , A.DVCLAS_NO , A.SBJCTNM , A.DEPT_ID , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_ID WHERE ORG_ID = #{orgId} AND DEPT_ID = A.DEPT_ID AND USEYN = 'Y') AS DEPTNM , A.SBJCT_ENNM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_CERT_STSCD , A.ATNDLC_APLY_MTHD_CD , A.QUOTA_LMTYN , A.ATNDLC_QUOTA , A.DPLM_OTPTYN , A.DPLM_SCRYN , A.FNSH_SCR , A.CRDTS , A.MID_ATNDC_CHK_USEYN , A.AIS_DATA_LNKGYN , A.MRK_OYN , A.CMCRS_GBNCD , A.MRK_PROC_SDTTM , A.MRK_PROC_EDTTM , A.MRK_OPEN_SDTTM , A.LCTR_TYCD , A.LRN_CNTRL , A.USEYN , A.KYWD , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , B.MRK_GRD_TYCD , B.MRK_EVL_TYCD , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD NOT IN ('D', 'T')) AS STD_TOTAL_CNT , (SELECT COUNT(*) FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID) AS TCH_TOTAL_CNT , (SELECT B2.USERNM FROM SBJCT_PROF B1, USR B2 WHERE B1.SBJCT_ID = A.SBJCT_ID AND B1.PROF_TYCD = 'PROFESSOR' AND B1.RPRSYN = 'Y' AND B1.USER_ID = B2.USER_ID) AS USERNM , (SELECT B2.USER_ID FROM SBJCT_PROF B1, TB_LMS_USER_ACNT B2 WHERE B1.SBJCT_ID = A.SBJCT_ID AND B1.PROF_TYCD = 'PROFESSOR' AND B1.RPRSYN = 'Y' AND B1.USER_ID = B2.USER_ID) AS USER_ID FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_CRE_CRS_EVAL B ON A.SBJCT_ID = B.SBJCT_ID INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID WHERE 1 = 1 AND A.DELYN = 'N' AND A.CRS_ID IN (SELECT CRS_ID FROM TB_LMS_CRS WHERE SBJCT_TYCD = 'UNI')
AND C.CRS_SMSTR_ID = #{termCd}
AND A.SBJCT_OP_TYCD = #{crsOperTypeCd}
AND ( LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.SBJCT_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM USR WHERE USER_ID = (SELECT USER_ID FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y'))) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.SBJCTNM, A.DEPT_ID, A.DVCLAS_NO ASC ) R ORDER BY LINE_NO DESC

