    )

mapper.select:
/* SQL ID : CreCrsDAO.coList 설 명 : 개설과목 리스트 (법정교육) */ SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_ID) AS LINE_NO , A.SBJCT_ID , A.CRS_ID , A.SBJCT_ID , A.CRS_ID , (SELECT USERNM FROM USR WHERE USER_ID = C.USER_ID) AS USERNM , C.USER_ID AS USER_ID , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , A.DVCLAS_NO , A.SBJCTNM , A.DEPT_ID , A.SBJCT_ENNM , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_CERT_STSCD , A.ATNDLC_APLY_MTHD_CD , IFNULL(A.QUOTA_LMTYN,'N') AS QUOTA_LMTYN , A.ATNDLC_QUOTA , A.DPLM_OTPTYN , A.DPLM_SCRYN , A.FNSH_SCR , A.CRDTS , A.MID_ATNDC_CHK_USEYN , A.AIS_DATA_LNKGYN , A.MRK_OYN , A.CMCRS_GBNCD , A.MRK_PROC_SDTTM , A.MRK_PROC_EDTTM , A.MRK_OPEN_SDTTM , A.LCTR_TYCD , A.LRN_CNTRL , A.USEYN , A.KYWD , (SELECT COUNT(*) FROM TB_LMS_SBJCT WHERE CRS_ID = A.CRS_ID AND SBJCT_ID = IFNULL(#{creYear}, SBJCT_ID)) AS CRE_CRS_CNT , B.ENRL_CERT_MTHD , B.SBJCT_TYCD , (SELECT COUNT(*) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD NOT IN ('D', 'E', 'N', 'T') ) AS STD_TOTAL_CNT , A.RGTR_ID , (SELECT USERNM FROM USR WHERE USER_ID = A.RGTR_ID) AS RGTRNM , A.FRST_INQ_DTTM , A.MDFR_ID , (SELECT USERNM FROM USR WHERE USER_ID = A.MDFR_ID) AS MOD_NM , A.MOD_DTTM FROM TB_LMS_SBJCT A INNER JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID LEFT JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.PROF_TYCD = 'PROFESSOR' AND C.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = #{crsTypeCd}
AND B.ORG_ID = #{orgId}
AND A.SBJCT_ID = #{creYear}
AND B.CRS_CTGRCD = (SELECT CRS_CTGRCD FROM TB_LMS_CRS_CTGR D WHERE D.CRS_CTGRCD = B.CRS_CTGRCD AND D.CRS_CTGRCD = #{crsCtgrCd} )
AND LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY SBJCT_ID DESC

/* SQL ID : CreCrsDAO.listPagingManageCourse 설 명 : 개설과목 관리 목록 페이징 */
SELECT ROW_NUMBER() OVER(ORDER BY A.DEPT_ID_ODR, A.DEPTNM, A.CRS_ID, A.DVCLAS_NO) AS LINE_NO , A.* FROM (
) A

/* SQL ID : CrecrsDAO.listAuthCrsCreByTerm 설 명 : 권한별 학기 개설과목 목록 */ SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.CRS_ID , B.CRS_SMSTR_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID
AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND B.CRS_SMSTR_ID = #{termCd}
WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND EXISTS ( SELECT 1 FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID
AND ( PROF_TYCD = 'PROFESSOR' OR PROF_TYCD = 'ASSOCIATE' )
AND PROF_TYCD = 'ASSISTANT'
AND USER_ID = #{userId} )

mapper.update:
/*
	 SQL ID : CreCrsDAO.updateCreCrsTermForTrans
	 설  명 : 과목 학기 수정(이관용)
*/
/* 학기 과목 연결 수정 */
UPDATE TB_LMS_TERM_CRE_CRS_RLTN
SET
	CRS_SMSTR_ID = #{transTermCd}
WHERE 1=1
	AND CRS_SMSTR_ID = #{termCd}
	AND SBJCT_ID = #{crsCreCd};

/* 과목 학기 정보 수정 */
UPDATE TB_LMS_SBJCT SET
	  SBJCT_ID = #{creYear}
	, CRS_ID = #{creTerm}
WHERE SBJCT_ID = #{crsCreCd};

/* JLPT 과목 주차 기간 수정 */
UPDATE TB_LMS_SBJCT_LCTR_SCHDL A
JOIN (
	SELECT
		  A.LCTR_SCHDL_ID
		, A.LCTR_SCHDL_SEQ
		, (SELECT SYMD FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd} AND TOC_SEQ = A.LCTR_SCHDL_SEQ LIMIT 1) AS LCTR_SYMD
		, (SELECT EYMD FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd} AND TOC_SEQ = A.LCTR_SCHDL_SEQ LIMIT 1) AS LCTR_EYMD
		, (SELECT MIN(LCTR_RCG_SYMD) FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd}) AS LCTR_RCG_SYMD
		, (SELECT MAX(LCTR_RCG_EYMD) FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd}) AS LCTR_RCG_EYMD
	FROM TB_LMS_SBJCT_LCTR_SCHDL A
	JOIN TB_LMS_SBJCT B
	ON A.SBJCT_ID = B.SBJCT_ID
	AND B.SBJCT_ID = #{crsCreCd}
	AND B.CRS_ID LIKE FN_LIKE_VAL('JLPT')
	WHERE A.SBJCT_ID = #{crsCreCd}
) B
ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID
SET   A.LCTR_SYMD = B.LCTR_SYMD
	, A.LCTR_EYMD = B.LCTR_EYMD
	, A.LCTR_RCG_SYMD = B.LCTR_RCG_SYMD
	, A.LCTR_RCG_EYMD = B.LCTR_RCG_EYMD;

/* JLPT 퀴즈 기간 수정 */
UPDATE TB_LMS_EXAM_BSC A
JOIN (
	SELECT
		  A.EXAM_ID
		, (SELECT MIN(IFNULL(LCTR_RCG_SYMD, SYMD)) FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd}) AS EXAM_SDTTM
		, (SELECT MAX(IFNULL(LCTR_RCG_EYMD, EYMD)) FROM CRS_SMSTR_WKNO WHERE CRS_SMSTR_ID = #{transTermCd}) AS EXAM_EDTTM
	FROM TB_LMS_EXAM_BSC A
	JOIN TB_LMS_EXAM_CRE_CRS_RLTN B
	ON A.EXAM_ID = B.EXAM_ID
	JOIN TB_LMS_SBJCT C
	ON B.SBJCT_ID = C.SBJCT_ID
	AND C.SBJCT_ID = #{crsCreCd}
	AND C.CRS_ID LIKE FN_LIKE_VAL('JLPT')
	WHERE A.EXAM_CTGRCD = 'QUIZ'
	AND A.EXAM_TYCD = 'QUIZ'
	AND A.TKEXAM_TYCD = 'A'
) B
ON A.EXAM_ID = B.EXAM_ID
SET	  A.EXAM_SDTTM = IF(B.EXAM_SDTTM IS NOT NULL, CONCAT(B.EXAM_SDTTM, '000000'), NULL)
	, A.EXAM_EDTTM = IF(B.EXAM_EDTTM IS NOT NULL, CONCAT(B.EXAM_EDTTM, '235959'), NULL);

mapper.delete:
/*
	 SQL ID : CreCrsDAO.deleteCreCrsDataForTrans
	 설  명 : 과목 학습활동 데이터 삭제(JLPT 이관용)
*/
/* 시험 응시 이력 삭제 */
DELETE X
FROM TB_LMS_EXAM_STARE_HSTY X
JOIN TB_LMS_EXAM_BSC A
	ON X.EXAM_ID = A.EXAM_ID
JOIN TB_LMS_EXAM_CRE_CRS_RLTN B
	ON A.EXAM_ID = B.EXAM_ID
	AND B.SBJCT_ID = #{crsCreCd};

/* 시험 응시 삭제 */
DELETE X
FROM TB_LMS_EXAM_STARE X
JOIN TB_LMS_EXAM_BSC A
	ON X.EXAM_ID = A.EXAM_ID
JOIN TB_LMS_EXAM_CRE_CRS_RLTN B
	ON A.EXAM_ID = B.EXAM_ID
	AND B.SBJCT_ID = #{crsCreCd};

/* 응시 시험지 이력 삭제 */
DELETE X
FROM TB_LMS_EXAM_STARE_PAPER_HSTY X
JOIN TB_LMS_EXAM_BSC A
	ON X.EXAM_ID = A.EXAM_ID
JOIN TB_LMS_EXAM_CRE_CRS_RLTN B
	ON A.EXAM_ID = B.EXAM_ID
	AND B.SBJCT_ID = #{crsCreCd};

/* 응시 시험지 삭제 */
DELETE X
FROM TB_LMS_EXAM_STARE_PAPER X
JOIN TB_LMS_EXAM_BSC A
	ON X.EXAM_ID = A.EXAM_ID
JOIN TB_LMS_EXAM_CRE_CRS_RLTN B
	ON A.EXAM_ID = B.EXAM_ID
	AND B.SBJCT_ID = #{crsCreCd};

/* 학습기록 상세 삭제 */
DELETE X
FROM TB_LMS_LESSON_STUDY_DETAIL X
JOIN TB_LMS_ATNDLC_SBJCT A
	ON X.STD_ID = A.STD_ID
	AND A.SBJCT_ID = #{crsCreCd};

/* 페이지 학습 기록 삭제 */
DELETE FROM TB_LMS_LESSON_STUDY_PAGE
WHERE SBJCT_ID = #{crsCreCd};

/* 주차별 학습 상황 삭제 */
DELETE FROM TB_LMS_LESSON_STUDY_STATE
WHERE SBJCT_ID = #{crsCreCd};

/* 수강생 학습 기록 삭제 */
DELETE X
FROM TB_LMS_LESSON_STUDY_RECORD X
JOIN TB_LMS_ATNDLC_SBJCT A
	ON X.STD_ID = A.STD_ID
	AND A.SBJCT_ID = #{crsCreCd};

/* 강의실 활동 이력 삭제 */
DELETE FROM TB_LOG_LESSON_ACTN_HSTY
WHERE SBJCT_ID = #{crsCreCd};

/* 학생성적이력 삭제 */
DELETE FROM TB_LMS_MRK_SBJCT_DTL
WHERE SBJCT_ID = #{crsCreCd};

/* 학생성적아이템별 삭제 */
DELETE X
FROM TB_LMS_STD_SCORE_ITEM X
JOIN TB_LMS_ATNDLC_SBJCT A
	ON X.STD_ID = A.STD_ID
	AND A.SBJCT_ID = #{crsCreCd};

/* 학생성적 삭제 */
DELETE X
FROM TB_LMS_MRK_SBJCT X
JOIN TB_LMS_ATNDLC_SBJCT A
	ON X.STD_ID = A.STD_ID
	AND A.SBJCT_ID = #{crsCreCd};

/* 수강생 삭제 */
DELETE FROM TB_LMS_ATNDLC_SBJCT
WHERE SBJCT_ID = #{crsCreCd};

mapper.update:
/*
	 SQL ID : CreCrsDAO.updateTmswPreTransState
	 설  명 : 선수과목 이관 완료여부 수정
*/
UPDATE TB_LMS_SBJCT
SET
	TMSW_PRRQST_SBJCT_BFRYN = #{tmswPreTransYn}
WHERE SBJCT_ID = #{crsCreCd}

mapper.select:
/* SQL ID : CreCrsDAO.listSbjctOfring 설 명 : 학위연도,기관,학기기수,학과에 따른 개설과목 조회 */ WITH SBJ_LIST AS ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , SMSTR.SMSTR_CHRT_ID , SMSTR.ORG_ID , ORG.ORGNM , A.DEPT_ID , DEPT.DEPTNM , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.PROF_ID , A.CRDTS FROM TB_LMS_SBJCT A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID JOIN TB_LMS_ORG ORG ON SMSTR.ORG_ID = ORG.ORG_ID LEFT JOIN TB_LMS_DEPT DEPT ON A.DEPT_ID = DEPT.DEPT_ID AND ORG.ORG_ID = DEPT.ORG_ID WHERE 1=1 AND A.DELYN = 'N' ) SELECT * FROM SBJ_LIST A WHERE 1=1 AND A.SBJCT_YR = #{sbjctYr}
AND A.SMSTR_CHRT_ID = #{smstrChrtId}
AND A.ORG_ID = #{orgId}
AND A.DEPT_ID = #{deptId}
